const theme=()=>{const themBtn=document.querySelector(".js--them-btn"),htmlDataset=document.documentElement.dataset;"dark"==htmlDataset.theme&&(themBtn.classList.toggle("ri-moon-line"),themBtn.classList.toggle("ri-sun-line")),themBtn.addEventListener("click",e=>{"white"===htmlDataset.theme?(htmlDataset.theme="dark",themBtn.classList.toggle("ri-sun-line"),themBtn.classList.toggle("ri-moon-line"),WrappedLocalStorage.set("wrapped-theme","dark")):(htmlDataset.theme="white",themBtn.classList.toggle("ri-moon-line"),themBtn.classList.toggle("ri-sun-line"),WrappedLocalStorage.set("wrapped-theme","white"))})};export default theme;